#include "log_softmax_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t MAX_TILE_ELEMS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    LogSoftmaxCustomTilingData tiling;
    const gert::StorageShape *storageShape = context->GetInputShape(0);
    const gert::Shape &originShape = storageShape->GetOriginShape();
    int32_t ndim = static_cast<int32_t>(originShape.GetDimNum());

    uint32_t numRows = 1;
    uint32_t rowLen = 1;
    if (ndim >= 2) {
        numRows = static_cast<uint32_t>(originShape.GetDim(0));
        rowLen = static_cast<uint32_t>(originShape.GetDim(ndim - 1));
        for (int32_t i = 1; i < ndim - 1; i++) {
            numRows *= static_cast<uint32_t>(originShape.GetDim(i));
        }
    } else if (ndim == 1) {
        numRows = 1;
        rowLen = static_cast<uint32_t>(originShape.GetDim(0));
    }

    uint32_t totalLength = numRows * rowLen;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *dimAttr = attrs->GetAttrPointer<int64_t>(0);
    int32_t dim = static_cast<int32_t>(*dimAttr);
    if (dim < 0) dim += ndim;

    // Compute tileLen: we need to fit 2 tiles (input + output) plus one for exp temp
    // In two-pass: first pass uses input tile + 1 scalar, second pass uses input + output tile.
    // Double buffering: inQueueX:2, outQueueY:2, tmpQueue:1 for exp (only in first pass)
    // Maximum simultaneous tiles = 2 (in) + 2 (out) + 1 (tmp) = 5
    // UB bytes = 5 * tileLen * sizeof(float) = 20 * tileLen
    uint32_t maxTile = UB_BUDGET_BYTES / 20;
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > MAX_TILE_ELEMS) maxTile = AlignDown(MAX_TILE_ELEMS, ALIGN_ELEMS);

    uint32_t tileLen = (rowLen < maxTile) ? rowLen : maxTile;
    tileLen = AlignDown(tileLen, ALIGN_ELEMS);
    if (tileLen == 0) tileLen = rowLen;  // fallback for small rows

    // Block dim: number of rows to process in parallel (one row per block)
    uint32_t blockDim = numRows;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;
    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_rowLength(rowLen);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_dim(dim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
