kernel_src="""
#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t rowLength,
                                uint32_t tileLength, float /*unused dim*/)
    {
        totalLen_ = totalLength;
        rowLen_ = rowLength;
        tileLen_ = tileLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        const uint32_t numRows = totalLen_ / rowLen_;
        if (blockIdx >= numRows) return;

        // This block processes one entire row.
        uint32_t rowStart = blockIdx * rowLen_;
        uint32_t numTiles = (rowLen_ + tileLen_ - 1) / tileLen_;

        // Phase 1: compute max and sum across the row (online softmax)
        float rowMax = -INFINITY;
        float rowSum = 0.0f;

        for (uint32_t t = 0; t < numTiles; t++) {
            uint32_t tileStart = rowStart + t * tileLen_;
            uint32_t curLen = tileLen_;
            if (tileStart + curLen > rowStart + rowLen_) {
                curLen = rowStart + rowLen_ - tileStart;
            }

            // Load tile
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[tileStart], curLen);
            inQueueX_.EnQue(xLocal);

            AscendC::LocalTensor<float> xDeq = inQueueX_.DeQue<float>();

            // Compute local max and sum of exp(x - local_max)
            AscendC::LocalTensor<float> expLocal = tmpQueue_.AllocTensor<float>();
            AscendC::LocalTensor<float> maxLocal = pipe_.AllocTensor<float>(1);
            AscendC::LocalTensor<float> sumLocal = pipe_.AllocTensor<float>(1);

            // local max
            AscendC::ReduceMax(maxLocal, xDeq, curLen);
            float localMaxVal = maxLocal(0);

            // new global max
            float newMax = (localMaxVal > rowMax) ? localMaxVal : rowMax;

            // adjust old sum: rowSum *= exp(rowMax - newMax)
            rowSum = rowSum * expf(rowMax - newMax);

            // compute exp(x - newMax) and accumulate
            AscendC::Subs(expLocal, xDeq, newMax, curLen);
            AscendC::Exp(expLocal, expLocal, curLen);
            AscendC::ReduceSum(sumLocal, expLocal, curLen);
            rowSum += sumLocal(0);

            rowMax = newMax;

            pipe_.FreeTensor(maxLocal);
            pipe_.FreeTensor(sumLocal);
            tmpQueue_.FreeTensor(expLocal);
            inQueueX_.FreeTensor(xDeq);
        }

        // Phase 2: compute output y = x - rowMax - log(rowSum)
        float logSum = logf(rowSum);
        for (uint32_t t = 0; t < numTiles; t++) {
            uint32_t tileStart = rowStart + t * tileLen_;
            uint32_t curLen = tileLen_;
            if (tileStart + curLen > rowStart + rowLen_) {
                curLen = rowStart + rowLen_ - tileStart;
            }

            // Load input tile
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[tileStart], curLen);
            inQueueX_.EnQue(xLocal);

            AscendC::LocalTensor<float> xDeq = inQueueX_.DeQue<float>();

            // Compute y = x - rowMax - logSum
            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            AscendC::Subs(yLocal, xDeq, rowMax, curLen);
            AscendC::Subs(yLocal, yLocal, logSum, curLen);

            // Store output
            outQueueY_.EnQue<float>(yLocal);
            AscendC::LocalTensor<float> yDeq = outQueueY_.DeQue<float>();
            AscendC::DataCopy(yGm_[tileStart], yDeq, curLen);
            outQueueY_.FreeTensor(yDeq);

            inQueueX_.FreeTensor(xDeq);
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t rowLen_ {0};
    uint32_t tileLen_ {0};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelLogSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.rowLength, tiling_data.tileLength);
    op.Process();
}
